//GRAVA PEDIDO
For Each Order EmpCod, FilCod, PedCod
	Where EmpCod = &EmpCod
	Where PedGUID = &sdtGetPedidosPDV.PedGUID when not &sdtGetPedidosPDV.PedGUID.IsEmpty()

	&PedCod = PedCod
	&PedSts = PedSts

	PedDtaEms = &sdtGetPedidosPDV.PedDtaEms
	PedHorEms = &sdtGetPedidosPDV.PedHorEms
	LctCod =  &sdtGetPedidosPDV.LctCod
	PedCliCod = &sdtGetPedidosPDV.PedCliCod

	if PedCliCod = &VistaPedCliCod
		PedNovCliRaz = &sdtGetPedidosPDV.PedNovCliRaz
	Endif

	PedVenCod = &sdtGetPedidosPDV.PedVenCod
	PedVlrLiq = &sdtGetPedidosPDV.PedVlrLiq
	PedVlrBrt = &sdtGetPedidosPDV.PedVlrBrt

	if &sdtGetPedidosPDV.PedDtaModSync.IsEmpty()
		pedDtaHorMod = ServerNow()
	Else
		pedDtaHorMod = &sdtGetPedidosPDV.PedDtaModSync
	Endif

	TabCod		= &sdtGetPedidosPDV.TabCod 
	TabPrmCod 	= &sdtGetPedidosPDV.TabPrmCod  
	TabColCod 	= &sdtGetPedidosPDV.TabColCod  
	PedPraCod 	 = &sdtGetPedidosPDV.PedPraCod 
	PedPraParNom = &sdtGetPedidosPDV.PedPraParNom 

	PedObsEst = &sdtGetPedidosPDV.PedObsEst
	PedObsFin  = &sdtGetPedidosPDV.PedObsFin
	PedObsGer = &sdtGetPedidosPDV.PedObsGer

	PedPerSpm1 = &sdtGetPedidosPDV.PedPerSpm1  
	PedPerSpm2 = &sdtGetPedidosPDV.PedPerSpm2 
	PedVlrDscGlb = &sdtGetPedidosPDV.PedVlrDscGlb 

	&UpdateInsert = 'UPD'
	Exit

When None
	UltimoCodigoEmpresa.call(domParCod.PEDIDO, &EmpCod, &FiLCod, &PedCod)

	new
		EmpCod = &Empcod
		FilCod = &FilCod
		PedCod = &PedCod		

		PedDtaEms = &sdtGetPedidosPDV.PedDtaEms
		PedHorEms = &sdtGetPedidosPDV.PedHorEms
		LctCod =  &sdtGetPedidosPDV.LctCod
		PedCliCod = &sdtGetPedidosPDV.PedCliCod

		if PedCliCod = &VistaPedCliCod
			PedNovCliRaz = &sdtGetPedidosPDV.PedNovCliRaz
		Endif

		PedVenCod = &sdtGetPedidosPDV.PedVenCod
		PedVlrLiq = &sdtGetPedidosPDV.PedVlrLiq
		PedVlrBrt = &sdtGetPedidosPDV.PedVlrBrt

		if &sdtGetPedidosPDV.PedDtaModSync.IsEmpty()
			pedDtaHorMod = ServerNow()
		Else
			pedDtaHorMod = &sdtGetPedidosPDV.PedDtaModSync
		Endif

		TabCod		= &sdtGetPedidosPDV.TabCod 
		TabPrmCod 	= &sdtGetPedidosPDV.TabPrmCod  
		TabColCod 	= &sdtGetPedidosPDV.TabColCod  
		PedPraCod 	 = &sdtGetPedidosPDV.PedPraCod 
		PedPraParNom = &sdtGetPedidosPDV.PedPraParNom 

		PedObsEst = &sdtGetPedidosPDV.PedObsEst
		PedObsFin  = &sdtGetPedidosPDV.PedObsFin
		PedObsGer = &sdtGetPedidosPDV.PedObsGer

		PedPerSpm1 = &sdtGetPedidosPDV.PedPerSpm1  
		PedPerSpm2 = &sdtGetPedidosPDV.PedPerSpm2 
		PedVlrDscGlb = &sdtGetPedidosPDV.PedVlrDscGlb		

		//CAMPOS INICIAIS PADROES
		PedSts = Status_pedido.ABERTO
		&PedSts = Status_pedido.ABERTO

		PedStsFin = Status_Financeiro.ABERTO	
		PedStsCrd = Status_Autorizado.AUTORIZADO
		PedBlq = Status_SimNao.Nao
		PedStsGer = Pedido_Gerado.PDV
		PedFatFilCod = FilCod

		PedGUID = &sdtGetPedidosPDV.PedGUID

		padraousuario.Call('G', 'JEAN2', 1, &EmpCod, 'PedGuid', &PadDtaMod)
	EndNEw

	padraousuario.Call('G', 'JEAN2', 1, &EmpCod, 'EndNEw', &PadDtaMod)
EndFor

padraousuario.Call('G', 'JEAN2', 1, &EmpCod, 'commit', &PadDtaMod)
commit

